(N'HADR_SYNCHRONIZING_THROTTLE',N'HA_REPLICATION',2,0,N'Waiting for transaction commit processing to allow a synchronizing secondary database to catch up to the primary end of log in order to transition to the synchronized state. This is an expected wait when a secondary database is catching up.',N'Availability Groups, Mirroring oder HA-Hintergrundarbeit.',N'Je Wait entweder erwarteter Idle-Zustand oder erhöhte Commit-/Redo-/Send-Latenz.',N'Benign-Flag beachten; Replica-Zustand, Queues, Netzwerk und Log-I/O prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'HADR_SYNC_COMMIT',N'HA_REPLICATION',4,0,N'Primäre Transaktion wartet auf Harden-Bestätigung einer synchronen Secondary.',N'Synchron-Commit-AG mit Netzwerk- oder Secondary-Log-I/O-Latenz.',N'Commit-Latenz des Primary steigt.',N'Log send queue, Netzwerk, Secondary Log Flush und Replica-Zustand prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'HADR_TDS_LISTENER_SYNC',N'HA_REPLICATION',2,0,N'Either the internal AlwaysOn system or the WSFC cluster will request that listeners are started or stopped. The processing of this request is always asynchronous, and there is a mechanism to remove redundant requests. There are also moments that this proc',N'Availability Groups, Mirroring oder HA-Hintergrundarbeit.',N'Je Wait entweder erwarteter Idle-Zustand oder erhöhte Commit-/Redo-/Send-Latenz.',N'Benign-Flag beachten; Replica-Zustand, Queues, Netzwerk und Log-I/O prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'HADR_TDS_LISTENER_SYNC_PROCESSING',N'HA_REPLICATION',2,0,N'Used at the end of an AlwaysOn Transact-SQL statement that requires starting and/or stopping anavailability group listener. Since the start/stop operation is done asynchronously, the user thread will block using this wait type until the situation of the l',N'Availability Groups, Mirroring oder HA-Hintergrundarbeit.',N'Je Wait entweder erwarteter Idle-Zustand oder erhöhte Commit-/Redo-/Send-Latenz.',N'Benign-Flag beachten; Replica-Zustand, Queues, Netzwerk und Log-I/O prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'HADR_TIMER_TASK',N'HA_REPLICATION',0,1,N'Waiting to get the lock on the timer task object and is also used for the actual waits between times that work is being performed. For example, for a task that runs every 10 seconds, after one execution, AlwaysOn Availability Groups waits about 10 seconds',N'Availability Groups, Mirroring oder HA-Hintergrundarbeit.',N'Je Wait entweder erwarteter Idle-Zustand oder erhöhte Commit-/Redo-/Send-Latenz.',N'Benign-Flag beachten; Replica-Zustand, Queues, Netzwerk und Log-I/O prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'HADR_TRANSPORT_DBRLIST',N'HA_REPLICATION',2,0,N'Waiting for access to the transport layers database replica list. Used for the spinlock that grants access to it.',N'Availability Groups, Mirroring oder HA-Hintergrundarbeit.',N'Je Wait entweder erwarteter Idle-Zustand oder erhöhte Commit-/Redo-/Send-Latenz.',N'Benign-Flag beachten; Replica-Zustand, Queues, Netzwerk und Log-I/O prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'HADR_TRANSPORT_FLOW_CONTROL',N'HA_REPLICATION',2,0,N'Waiting when the number of outstanding unacknowledged AlwaysOn messages is over the out flow control threshold. This is on an availability replica-to-replica basis (not on a database-to-database basis).',N'Availability Groups, Mirroring oder HA-Hintergrundarbeit.',N'Je Wait entweder erwarteter Idle-Zustand oder erhöhte Commit-/Redo-/Send-Latenz.',N'Benign-Flag beachten; Replica-Zustand, Queues, Netzwerk und Log-I/O prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'HADR_TRANSPORT_SESSION',N'HA_REPLICATION',2,0,N'AlwaysOn Availability Groups is waiting while changing or accessing the underlying transport state.',N'Availability Groups, Mirroring oder HA-Hintergrundarbeit.',N'Je Wait entweder erwarteter Idle-Zustand oder erhöhte Commit-/Redo-/Send-Latenz.',N'Benign-Flag beachten; Replica-Zustand, Queues, Netzwerk und Log-I/O prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'HADR_WORK_POOL',N'HA_REPLICATION',2,0,N'Concurrency control wait on the AlwaysOn Availability Groups background work task object.',N'Availability Groups, Mirroring oder HA-Hintergrundarbeit.',N'Je Wait entweder erwarteter Idle-Zustand oder erhöhte Commit-/Redo-/Send-Latenz.',N'Benign-Flag beachten; Replica-Zustand, Queues, Netzwerk und Log-I/O prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'HADR_WORK_QUEUE',N'HA_REPLICATION',0,1,N'AlwaysOn Availability Groups background worker thread waiting for new work to be assigned. This is an expected wait when there are ready workers waiting for new work, which is the normal state.',N'Availability Groups, Mirroring oder HA-Hintergrundarbeit.',N'Je Wait entweder erwarteter Idle-Zustand oder erhöhte Commit-/Redo-/Send-Latenz.',N'Benign-Flag beachten; Replica-Zustand, Queues, Netzwerk und Log-I/O prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'HADR_XRF_STACK_ACCESS',N'HA_REPLICATION',2,0,N'Accessing (look up, add, and delete) the extended recovery fork stack for an AlwaysOn availability database.',N'Availability Groups, Mirroring oder HA-Hintergrundarbeit.',N'Je Wait entweder erwarteter Idle-Zustand oder erhöhte Commit-/Redo-/Send-Latenz.',N'Benign-Flag beachten; Replica-Zustand, Queues, Netzwerk und Log-I/O prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'HTDELETE',N'OTHER_OR_NEW',2,0,N'This wait type (and the other HT* waits) is when a thread is waiting for access to the shared hash table used during batch-mode processing. SQL Server 2012 used to use a hash table per thread and SQL Server 2014 now uses a shared hash table. This change was made to reduce the amount of memory required for the hash table, but comes at the expense of these waits when synchronizing access to the hash table. Typically these waits occur when queries involve columnstore indexes, but they can also occur without columnstore indexes being involved if a hash operator runs in batch mode.',N'Spezialisierter, interner oder neuer SQL-Server-Wait-Type.',N'Hohe Werte sind nur im Delta- und Workload-Kontext bewertbar.',N'Aktive Tasks, Ressource, Version, Microsoft-Referenz und Versionskontext prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'HTTP_ENUMERATION',N'OTHER_OR_NEW',2,0,N'Occurs at startup to enumerate the HTTP endpoints to start HTTP.',N'Spezialisierter, interner oder neuer SQL-Server-Wait-Type.',N'Hohe Werte sind nur im Delta- und Workload-Kontext bewertbar.',N'Aktive Tasks, Ressource, Version, Microsoft-Referenz und Versionskontext prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'HTTP_START',N'OTHER_OR_NEW',2,0,N'Occurs when a connection is waiting for HTTP to complete initialization.',N'Spezialisierter, interner oder neuer SQL-Server-Wait-Type.',N'Hohe Werte sind nur im Delta- und Workload-Kontext bewertbar.',N'Aktive Tasks, Ressource, Version, Microsoft-Referenz und Versionskontext prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'IMPPROV_IOWAIT',N'OTHER_OR_NEW',2,0,N'Occurs when SQL Server waits for a bulkload I/O to finish.',N'Spezialisierter, interner oder neuer SQL-Server-Wait-Type.',N'Hohe Werte sind nur im Delta- und Workload-Kontext bewertbar.',N'Aktive Tasks, Ressource, Version, Microsoft-Referenz und Versionskontext prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'INTERNAL_TESTING',N'OTHER_OR_NEW',2,0,N'Identified for informational purposes only. Not supported. Future compatibility is not guaranteed.',N'Spezialisierter, interner oder neuer SQL-Server-Wait-Type.',N'Hohe Werte sind nur im Delta- und Workload-Kontext bewertbar.',N'Aktive Tasks, Ressource, Version, Microsoft-Referenz und Versionskontext prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'IOAFF_RANGE_QUEUE',N'OTHER_OR_NEW',2,0,N'Identified for informational purposes only. Not supported. Future compatibility is not guaranteed.',N'Spezialisierter, interner oder neuer SQL-Server-Wait-Type.',N'Hohe Werte sind nur im Delta- und Workload-Kontext bewertbar.',N'Aktive Tasks, Ressource, Version, Microsoft-Referenz und Versionskontext prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'IO_AUDIT_MUTEX',N'STORAGE_DATA_IO',2,0,N'Occurs during synchronization of trace event buffers.',N'Daten-, Metadaten- oder asynchroner Datei-I/O.',N'Hohe Delta-Werte können auf Storage-Latenz, Scans oder Buffer-Pool-Druck hinweisen.',N'sys.dm_io_virtual_file_stats, Volume, Buffer Pool, große Reads und aktive Operation korrelieren.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'IO_COMPLETION',N'STORAGE_DATA_IO',3,0,N'Warten auf Abschluss eines nicht näher spezialisierten I/O-Vorgangs.',N'Dateizugriffe, Metadaten-I/O, Backup oder andere asynchrone I/O-Pfade.',N'I/O-Latenz kann Serveroperationen und Abfragen verzögern.',N'File- und Volume-Latenzen sowie gleichzeitig aktive Operationen korrelieren.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'IO_RETRY',N'STORAGE_DATA_IO',2,0,N'Occurs when an I/O operation such as a read or a write to disk fails because of insufficient resources, and is then retried.',N'Daten-, Metadaten- oder asynchroner Datei-I/O.',N'Hohe Delta-Werte können auf Storage-Latenz, Scans oder Buffer-Pool-Druck hinweisen.',N'sys.dm_io_virtual_file_stats, Volume, Buffer Pool, große Reads und aktive Operation korrelieren.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'KSOURCE_WAKEUP',N'BENIGN_BACKGROUND',0,1,N'Used by the service control task while waiting for requests from the Service Control Manager. Long waits are expected and do not indicate a problem.',N'Normaler Idle-, Timer-, Queue- oder Hintergrundzustand.',N'Hohe kumulative Werte sind in der Regel erwartbar und kein Engpassbeweis.',N'Standardmäßig aus Top-Ranking ausblenden; nur bei passender Funktionsstörung untersuchen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'KTM_ENLISTMENT',N'OTHER_OR_NEW',2,0,N'Identified for informational purposes only. Not supported. Future compatibility is not guaranteed.',N'Spezialisierter, interner oder neuer SQL-Server-Wait-Type.',N'Hohe Werte sind nur im Delta- und Workload-Kontext bewertbar.',N'Aktive Tasks, Ressource, Version, Microsoft-Referenz und Versionskontext prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'KTM_RECOVERY_MANAGER',N'OTHER_OR_NEW',2,0,N'Identified for informational purposes only. Not supported. Future compatibility is not guaranteed.',N'Spezialisierter, interner oder neuer SQL-Server-Wait-Type.',N'Hohe Werte sind nur im Delta- und Workload-Kontext bewertbar.',N'Aktive Tasks, Ressource, Version, Microsoft-Referenz und Versionskontext prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'KTM_RECOVERY_RESOLUTION',N'OTHER_OR_NEW',2,0,N'Identified for informational purposes only. Not supported. Future compatibility is not guaranteed.',N'Spezialisierter, interner oder neuer SQL-Server-Wait-Type.',N'Hohe Werte sind nur im Delta- und Workload-Kontext bewertbar.',N'Aktive Tasks, Ressource, Version, Microsoft-Referenz und Versionskontext prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'LATCH_DT',N'INTERNAL_SYNCHRONIZATION',2,0,N'Latch löschen - Occurs when waiting for a DT (destroy) latch. This does not include buffer latches or transaction mark latches. A listing of LATCH_* waits is available in sys.dm_os_latch_stats. Note that sys.dm_os_latch_stats groups LATCH_NL, LATCH_SH, LATCH_UP, LATCH_EX',N'Interne Synchronisation von Speicher- oder Engine-Strukturen.',N'Hohe Delta-Werte können auf interne Hotspots oder Workload-Skalierungsgrenzen hinweisen.',N'Konkrete Wait-Detailseite, Spinlocks/Latches, Plan Cache und Workload-Korrelation prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'LATCH_EX',N'INTERNAL_SYNCHRONIZATION',2,0,N'Exklusiver Latch - Occurs when waiting for an EX (exclusive) latch. This does not include buffer latches or transaction mark latches. A listing of LATCH_* waits is available in sys.dm_os_latch_stats. Note that sys.dm_os_latch_stats groups LATCH_NL, LATCH_SH, LATCH_UP, LATCH',N'Interne Synchronisation von Speicher- oder Engine-Strukturen.',N'Hohe Delta-Werte können auf interne Hotspots oder Workload-Skalierungsgrenzen hinweisen.',N'Konkrete Wait-Detailseite, Spinlocks/Latches, Plan Cache und Workload-Korrelation prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'LATCH_KP',N'INTERNAL_SYNCHRONIZATION',2,0,N'Warten auf einen Keep-Latch; Buffer-Latches und Transaction-Mark-Latches sind nicht enthalten.',N'Interne Synchronisation von Speicher- oder Engine-Strukturen.',N'Hohe Delta-Werte können auf interne Hotspots oder Workload-Skalierungsgrenzen hinweisen.',N'Konkrete Latchklasse in sys.dm_os_latch_stats, Plan Cache und Workload-Korrelation prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'LATCH_NL',N'INTERNAL_SYNCHRONIZATION',2,0,N'Kein Latch - Identified for informational purposes only. Not supported. Future compatibility is not guaranteed.',N'Interne Synchronisation von Speicher- oder Engine-Strukturen.',N'Hohe Delta-Werte können auf interne Hotspots oder Workload-Skalierungsgrenzen hinweisen.',N'Konkrete Wait-Detailseite, Spinlocks/Latches, Plan Cache und Workload-Korrelation prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'LATCH_SH',N'INTERNAL_SYNCHRONIZATION',2,0,N'Gemeinsam genutzter Latch - Occurs when waiting for an SH (share) latch. This does not include buffer latches or transaction mark latches. A listing of LATCH_* waits is available in sys.dm_os_latch_stats. Note that sys.dm_os_latch_stats groups LATCH_NL, LATCH_SH, LATCH_UP, LATCH_EX,',N'Interne Synchronisation von Speicher- oder Engine-Strukturen.',N'Hohe Delta-Werte können auf interne Hotspots oder Workload-Skalierungsgrenzen hinweisen.',N'Konkrete Wait-Detailseite, Spinlocks/Latches, Plan Cache und Workload-Korrelation prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'LATCH_UP',N'INTERNAL_SYNCHRONIZATION',2,0,N'Latch aktualisieren - Occurs when waiting for an UP (update) latch. This does not include buffer latches or transaction mark latches. A listing of LATCH_* waits is available in sys.dm_os_latch_stats. Note that sys.dm_os_latch_stats groups LATCH_NL, LATCH_SH, LATCH_UP, LATCH_EX',N'Interne Synchronisation von Speicher- oder Engine-Strukturen.',N'Hohe Delta-Werte können auf interne Hotspots oder Workload-Skalierungsgrenzen hinweisen.',N'Konkrete Wait-Detailseite, Spinlocks/Latches, Plan Cache und Workload-Korrelation prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'LAZYWRITER_SLEEP',N'BENIGN_BACKGROUND',0,1,N'Lazy Writer wartet zwischen Arbeitszyklen.',N'Normaler Leerlauf des Buffer-Pool-Hintergrundtasks.',N'Hohe kumulative Werte sind erwartbar.',N'Nicht als Problem interpretieren.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'LCK_M_BU',N'LOCKING',4,0,N'Massenaktualisierungssperre - Occurs when a task is waiting to acquire a Bulk Update (BU) lock. For a lock compatibility matrix, seesys.dm_tran_locks (Transact-SQL).',N'Konkurrierende Sperren oder lange Transaktionen.',N'Hohe Delta-Werte verursachen Blocking, Timeouts und reduzierten Durchsatz.',N'Root Blocker, offene Transaktionen, Isolation Level, Zugriffsmuster und Indizes prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'LCK_M_IS',N'LOCKING',4,0,N'Beabsichtigt-Gemeinsam - Occurs when a task is waiting to acquire an Intent Shared (IS) lock. For a lock compatibility matrix, seesys.dm_tran_locks (Transact-SQL).',N'Konkurrierende Sperren oder lange Transaktionen.',N'Hohe Delta-Werte verursachen Blocking, Timeouts und reduzierten Durchsatz.',N'Root Blocker, offene Transaktionen, Isolation Level, Zugriffsmuster und Indizes prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'LCK_M_IU',N'LOCKING',4,0,N'Beabsichtigt-Aktualisierung - Occurs when a task is waiting to acquire an Intent Update (IU) lock. For a lock compatibility matrix, seesys.dm_tran_locks (Transact-SQL).',N'Konkurrierende Sperren oder lange Transaktionen.',N'Hohe Delta-Werte verursachen Blocking, Timeouts und reduzierten Durchsatz.',N'Root Blocker, offene Transaktionen, Isolation Level, Zugriffsmuster und Indizes prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'LCK_M_IX',N'LOCKING',4,0,N'Beabsichtigt-Exklusiv - Occurs when a task is waiting to acquire an Intent Exclusive (IX) lock. For a lock compatibility matrix, seesys.dm_tran_locks (Transact-SQL).',N'Konkurrierende Sperren oder lange Transaktionen.',N'Hohe Delta-Werte verursachen Blocking, Timeouts und reduzierten Durchsatz.',N'Root Blocker, offene Transaktionen, Isolation Level, Zugriffsmuster und Indizes prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'LCK_M_RIn_NL',N'LOCKING',4,0,N'Warten auf einen sofort freigegebenen NULL-Lock am aktuellen Schlüssel und einen Insert-Range-Lock zwischen aktuellem und vorherigem Schlüssel.',N'Konkurrierende Sperren oder lange Transaktionen.',N'Hohe Delta-Werte verursachen Blocking, Timeouts und reduzierten Durchsatz.',N'Root Blocker, offene Transaktionen, Isolation Level, Zugriffsmuster und Indizes prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'LCK_M_RIn_S',N'LOCKING',4,0,N'Warten auf einen Shared Lock am aktuellen Schlüssel und einen Insert-Range-Lock zwischen aktuellem und vorherigem Schlüssel.',N'Konkurrierende Sperren oder lange Transaktionen.',N'Hohe Delta-Werte verursachen Blocking, Timeouts und reduzierten Durchsatz.',N'Root Blocker, offene Transaktionen, Isolation Level, Zugriffsmuster und Indizes prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'LCK_M_RIn_U',N'LOCKING',4,0,N'Warten auf einen Update Lock am aktuellen Schlüssel und einen Insert-Range-Lock zwischen aktuellem und vorherigem Schlüssel.',N'Konkurrierende Sperren oder lange Transaktionen.',N'Hohe Delta-Werte verursachen Blocking, Timeouts und reduzierten Durchsatz.',N'Root Blocker, offene Transaktionen, Isolation Level, Zugriffsmuster und Indizes prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'LCK_M_RIn_X',N'LOCKING',4,0,N'Warten auf einen Exclusive Lock am aktuellen Schlüssel und einen Insert-Range-Lock zwischen aktuellem und vorherigem Schlüssel.',N'Konkurrierende Sperren oder lange Transaktionen.',N'Hohe Delta-Werte verursachen Blocking, Timeouts und reduzierten Durchsatz.',N'Root Blocker, offene Transaktionen, Isolation Level, Zugriffsmuster und Indizes prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED'),
(N'LCK_M_RS_S',N'LOCKING',4,0,N'Bereich-Gemeinsam-Gemeinsam (Range-share-share) - Occurs when a task is waiting to acquire a Shared lock on the current key value, and a Shared Range lock between the current and previous key. For a lock compatibility matrix, see sys.dm_tran_locks (Transact-SQL).',N'Konkurrierende Sperren oder lange Transaktionen.',N'Hohe Delta-Werte verursachen Blocking, Timeouts und reduzierten Durchsatz.',N'Root Blocker, offene Transaktionen, Isolation Level, Zugriffsmuster und Indizes prüfen.',N'FRAMEWORK_CURATED',N'FRAMEWORK_CURATED');

UPDATE [c] SET [WaitGroup]=[s].[WaitGroup],[Severity]=[s].[Severity],[IsGenerallyBenign]=[s].[IsGenerallyBenign],[Meaning]=[s].[Meaning],
 [TypicalOccurrence]=[s].[TypicalOccurrence],[HighWaitImpact]=[s].[HighWaitImpact],[RecommendedChecks]=[s].[RecommendedChecks],
 [HelpUrl]=N'https://www.sqlskills.com/help/waits/'+[s].[WaitType],[DescriptionSource]=[s].[DescriptionSource],
 [DescriptionQuality]=[s].[DescriptionQuality],[SourceReference]=N'https://learn.microsoft.com/en-us/sql/relational-databases/system-dynamic-management-objects/sys-dm-os-wait-stats-transact-sql?view=sql-server-ver17',
 [IsFrameworkDefault]=1,[LastUpdatedUtc]=SYSUTCDATETIME()
FROM [monitor].[WaitTypeCatalog] [c] JOIN @Seed [s] ON [s].[WaitType]=[c].[WaitType] WHERE [c].[IsFrameworkDefault]=1;

INSERT [monitor].[WaitTypeCatalog]
([WaitType],[WaitGroup],[Severity],[IsGenerallyBenign],[Meaning],[TypicalOccurrence],[HighWaitImpact],[RecommendedChecks],[HelpUrl],
 [DescriptionSource],[DescriptionQuality],[SourceReference],[IsFrameworkDefault])
SELECT [s].[WaitType],[s].[WaitGroup],[s].[Severity],[s].[IsGenerallyBenign],[s].[Meaning],[s].[TypicalOccurrence],[s].[HighWaitImpact],[s].[RecommendedChecks],
 N'https://www.sqlskills.com/help/waits/'+[s].[WaitType],[s].[DescriptionSource],[s].[DescriptionQuality],
 N'https://learn.microsoft.com/en-us/sql/relational-databases/system-dynamic-management-objects/sys-dm-os-wait-stats-transact-sql?view=sql-server-ver17',1
FROM @Seed [s] WHERE NOT EXISTS(SELECT 1 FROM [monitor].[WaitTypeCatalog] [c] WHERE [c].[WaitType]=[s].[WaitType]);
GO
